-- SQLite schema illustrating simple SQL theory (3 tables: authors, books, reviews) with constraints and sample data

CREATE TABLE authors (
  author_id INTEGER PRIMARY KEY,
  name TEXT NOT NULL
);

CREATE TABLE books (
  book_id INTEGER PRIMARY KEY,
  title TEXT NOT NULL,
  author_id INTEGER NOT NULL,
  year_published INTEGER,
  FOREIGN KEY (author_id) REFERENCES authors(author_id)
);

CREATE TABLE reviews (
  review_id INTEGER PRIMARY KEY,
  book_id INTEGER NOT NULL,
  rating INTEGER NOT NULL CHECK (rating >= 1 AND rating <= 5),
  comment TEXT,
  FOREIGN KEY (book_id) REFERENCES books(book_id)
);

-- Sample data
INSERT INTO authors (author_id, name) VALUES (1, 'Jane Austen'), (2, 'George Orwell');
INSERT INTO books (book_id, title, author_id, year_published) VALUES (1, 'Pride and Prejudice', 1, 1813), (2, '1984', 2, 1949);
INSERT INTO reviews (review_id, book_id, rating, comment) VALUES (1, 1, 5, 'Classic romance satire'), (2, 2, 5, 'Dystopian classic');

-- Index to optimize join between books and authors
CREATE INDEX idx_books_author ON books(author_id);
